var e=[{id:`L3_1`,type:`dialog`,speaker:`PHOTO_EXTRA_NULL_A`,text:{KOREA:`돌아왔다! 샤레이드의 챔피언들이 돌아왔어!`,JPN:`戻ってきた！　シャレードのチャンピオンたちが戻ってきたぞ！`,ENG:`They're back! Charade's champions have returned!`,TWN:`她們回來了！查雷德的冠軍們回來了！`},stage:{bg:`GAUNTLET`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`PHOTO_EXTRA_NULL_B`,text:{KOREA:`코핀 컴퍼니의 펜릴 소대에게 시민들을 대표해 감사의 말씀을 전해드리고 싶은데요! 잠시 인터뷰에 응해 주실 수 있을까요?!`,JPN:`コフィンカンパニーのフェンリル小隊に市民を代表し感謝の言葉を伝えたいのですが！　ちょっとだけインタビューに応じて頂けますか！？`,ENG:`Excuse me! On behalf of all the citizens. I'd like to express our gratitude for Coffin Company's Fenrir Squad! Also, would you mind doing a small interview?!`,TWN:`我想代表市民感謝科芬公司的芬里爾小隊，請問你們是否願意接受一次簡短的採訪？！`},stage:{bg:`GAUNTLET`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`PHOTO_EXTRA_NULL_C`,text:{KOREA:`그로니아의 무공수훈자인 크리스티나 브레히트 양과 호흡을 맞춰 싸우던데 두 분과는 어떤 관계이십니까?`,JPN:`グロニアの受勲者であるクリスティーナ・ブレヒトさんとともに戦っていましたけど、二人はどのような関係ですか？`,ENG:`We saw you fighting alongside Christina Brecht, Gronia's war hero who received the Medal of Honor.  May I ask what your relationship is with her?`,TWN:`我們看到你一直與格羅尼亞的授勳者克莉絲蒂娜·布萊希特並肩作戰，請問你們是什麼關係？`},stage:{bg:`GAUNTLET`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`PHOTO_EXTRA_NULL_D`,text:{KOREA:`그녀가 현재 본국에서 지명수배되고 있다는 사실은 알고 계신가요?! 지금 어디에 있죠?!`,JPN:`彼女が現在本国では指名手配されていることは知っていますか！？　今はどこにいるんですか！？`,ENG:`Did you know that she is currently a wanted criminal in her own country?! Where is she now?!`,TWN:`你知道她目前已被本國通緝的事實嗎？她現在在哪裡？`},stage:{bg:`GAUNTLET`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`자, 자, 응급환자입니다. 다 죽어가는 영웅 앞길 막지 말고 옆으로 비켜주세요.`,JPN:`さぁ、さぁ、救急患者ですよ。死にかけている英雄の前をふさがないで横にどいてくださいね。`,ENG:`Hey, emergency patient comin' through. Step aside if you don't want the hero to die.`,TWN:`好了，好了，這位是急救患者，我們的英雄需要治療，請讓一下。`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`이 천장… 이젠 낯설지가 않네.`,JPN:`この天井……もう見飽きたな。`,ENG:`This ceiling... It's so familiar now.`,TWN:`這個天花板……不再那麼陌生了。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`선배님! 제가 밥 가져왔어요!`,JPN:`先輩！　ご飯を持ってきました！`,ENG:`Mina! I brought you your food!`,TWN:`前輩，我給你帶了些吃的！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`노엘?`,JPN:`ノエル？`,ENG:`Noelle?`,TWN:`洛艾兒？`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`왜 네가 그걸 가져와? 너 다리에 깁스하고 있잖아. 의사가 특히 꼬리뼈를 조심하라던데.`,JPN:`何であなたがそんなことするの？　脚にギプスをつけているのに。医者が特に尾骨には気を付けろって言ったよね。`,ENG:`Why are you bringing that? You have a cast on your leg. Didn't the doctor tell you to be especially careful about your tailbone?`,TWN:`為什麼是你給我帶來？你腿上打著石膏，而且醫生說要特別小心你的尾椎。`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`괜찮아요. 선배님이 싸인 해 주신 덕분에 금방 나았…`,JPN:`大丈夫です。先輩がしてくれたサインのおかげですぐ治っ……`,ENG:`It's all right. You signed my cast, so I'll be good in no ti–`,TWN:`沒關係，多虧了你的親筆簽名，我很快就好……`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`꺄앗!!`,JPN:`きゃあっ！！`,ENG:`Kyaah!`,TWN:`呀啊！！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`흐아앙, 괜찮으세요?`,JPN:`ふええん、大丈夫ですか？`,ENG:`Waah... Are you okay?`,TWN:`嗚嗚，你還好嗎？`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`…정수리가 국 때문에 뜨거워.`,JPN:`……頭が汁のせいで熱い。`,ENG:`...You poured hot soup all over my head.`,TWN:`……湯灑在我頭上了。`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`수, 수건 금방 가져올게요!`,JPN:`タ、タオルを取ってきます！`,ENG:`I-I'll be right back with some towels!`,TWN:`我，我馬上去拿毛巾！`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`}}}}];export{e as default};